  1→/**
  2→ * Agent Activator
  3→ *
  4→ * POST endpoint handler called by SurrealDB DEFINE EVENT webhook when
  5→ * observations are created. Uses LLM classification to determine which
  6→ * registered agent types should be activated for a given observation,
  7→ * then starts new agent sessions for matched agents.
  8→ *
  9→ * Observations targeting entities with active agent sessions are skipped —
 10→ * the LLM proxy handles enriching those sessions via its own vector search.
 11→ *
 12→ * LLM classification over KNN because the question is "which agents can
 13→ * ACT on this observation?" — a judgment problem, not a proximity problem.
 14→ * See ADR-061.
 15→ *
 16→ * Step: 03-02 (Graph-Reactive Coordination)
 17→ */
 18→import { RecordId, type Surreal } from "surrealdb";
 19→import { generateObject, type LanguageModel } from "ai";
 20→import { z } from "zod";
 21→import { log } from "../telemetry/logger";
 22→import type { LoopDampener, DampenerEvent } from "./loop-dampener";
 23→
 24→// ---------------------------------------------------------------------------
 25→// Domain Types
 26→// ---------------------------------------------------------------------------
 27→
 28→/** Webhook payload from SurrealDB DEFINE EVENT on observation CREATE. */
 29→export type ObservationWebhookPayload = {
 30→  observation_id: string;
 31→  workspace: string;
 32→  text: string;
 33→  severity: string;
 34→  source_agent: string;
 35→};
 36→
 37→/** A registered agent type with its description. */
 38→export type RegisteredAgent = {
 39→  agentId: string;
 40→  agentType: string;
 41→  description: string;
 42→};
 43→
 44→/** An agent matched by LLM classification for activation. */
 45→export type AgentActivation = {
 46→  agentId: string;
 47→  agentType: string;
 48→  workspaceId: string;
 49→  reason: string;
 50→  observationId: string;
 51→  observationText: string;
 52→};
 53→
 54→/** Callback invoked when the activator decides to start a new agent. */
 55→export type OnAgentActivation = (activation: AgentActivation) => void;
 56→
 57→/** Inflight tracker for background async work. */
 58→export type InflightTracker = {
 59→  track: (promise: Promise<unknown>) => void;
 60→};
 61→
 62→/** Dependencies injected into the agent activator. */
 63→export type AgentActivatorDeps = {
 64→  surreal: Surreal;
 65→  loopDampener: LoopDampener;
 66→  inflight: InflightTracker;
 67→  classifierModel: LanguageModel;
 68→  onAgentActivation: OnAgentActivation;
 69→  /** Shared secret for webhook authentication. If undefined, all requests are allowed (dev mode). */
 70→  internalWebhookSecret?: string;
 71→};
 72→
 73→// ---------------------------------------------------------------------------
 74→// Pure Functions
 75→// ---------------------------------------------------------------------------
 76→
 77→/**
 78→ * Parses and validates the webhook payload from SurrealDB DEFINE EVENT.
 79→ * Returns undefined if the payload is invalid.
 80→ */
 81→export function parseWebhookPayload(
 82→  body: unknown,
 83→): ObservationWebhookPayload | undefined {
 84→  if (!body || typeof body !== "object") return undefined;
 85→  const b = body as Record<string, unknown>;
 86→
 87→  const rawObsId = b.observation_id;
 88→  const workspace = b.workspace;
 89→  const text = b.text;
 90→  const severity = b.severity;
 91→  const source_agent = b.source_agent;
 92→
 93→  if (
 94→    typeof text !== "string" ||
 95→    typeof severity !== "string" ||
 96→    typeof source_agent !== "string" ||
 97→    !rawObsId ||
 98→    !workspace
 99→  ) {
100→    return undefined;
101→  }
102→
103→  // observation_id may be a string "observation:id", a bare id, or a RecordId object
104→  let observationId: string;
105→  if (typeof rawObsId === "string") {
106→    observationId = rawObsId.includes(":") ? rawObsId.split(":").slice(1).join(":") : rawObsId;
107→  } else if (rawObsId instanceof RecordId) {
108→    observationId = rawObsId.id as string;
109→  } else {
110→    return undefined;
111→  }
112→
113→  // workspace may be a string "workspace:id", a bare id, or a RecordId object
114→  let workspaceId: string;
115→  if (typeof workspace === "string") {
116→    workspaceId = workspace.includes(":") ? workspace.split(":").slice(1).join(":") : workspace;
117→  } else if (workspace instanceof RecordId) {
118→    workspaceId = workspace.id as string;
119→  } else {
120→    return undefined;
121→  }
122→
123→  return {
124→    observation_id: observationId,
125→    workspace: workspaceId,
126→    text,
127→    severity,
128→    source_agent,
129→  };
130→}
131→
132→/**
133→ * Validates the webhook request's Authorization header against the shared secret.
134→ * Returns true if the secret is not configured (dev mode) or if the header matches.
135→ */
136→export function validateWebhookSecret(
137→  authHeader: string | undefined,
138→  secret: string | undefined,
139→): boolean {
140→  if (!secret) return true; // dev mode: no secret configured, allow all
141→  if (!authHeader) return false;
142→  return authHeader === `Bearer ${secret}`;
143→}
144→
145→/**
146→ * Builds a dampener event key from webhook payload fields.
147→ */
148→export function buildDampenerEvent(
149→  workspaceId: string,
150→  entityId: string,
151→  sourceAgent: string,
152→): DampenerEvent {
153→  return { workspaceId, entityId, sourceAgent };
154→}
155→
156→/**
157→ * Builds the LLM classification prompt from observation + agent descriptions.
158→ */
159→export function buildClassificationPrompt(
160→  observation: { text: string; severity: string },
161→  agents: ReadonlyArray<RegisteredAgent>,
162→): string {
163→  const agentList = agents
164→    .map((a) => `- Agent "${a.agentId}" (type: ${a.agentType}): ${a.description}`)
165→    .join("\n");
166→
167→  return `You are an agent activator. Given an observation from a knowledge graph, determine which registered agents should be started to handle it.
168→
169→## Observation
170→Severity: ${observation.severity}
171→Text: ${observation.text}
172→
173→## Registered Agents
174→${agentList}
175→
176→## Instructions
177→- Select agents that can TAKE ACTION on this observation (not just agents with related keywords)
178→- Consider the severity: conflict observations need immediate action, info observations may not need any agent
179→- If no agent is relevant, return an empty list
180→- For each selected agent, explain briefly why it should be activated`;
181→}
182→
183→// ---------------------------------------------------------------------------
184→// LLM Classification Schema
185→// ---------------------------------------------------------------------------
186→
187→const classificationSchema = z.object({
188→  activations: z.array(z.object({
189→    agent_id: z.string().describe("The agent ID to activate"),
190→    reason: z.string().describe("Brief explanation of why this agent should handle the observation"),
191→  })),
192→});
193→
194→// ---------------------------------------------------------------------------
195→// DB Queries (Side-Effect Boundary)
196→// ---------------------------------------------------------------------------
197→
198→/**
199→ * Loads all registered agents for a workspace (via identity membership).
200→ */
201→async function loadWorkspaceAgents(
202→  surreal: Surreal,
203→  workspaceId: string,
204→): Promise<RegisteredAgent[]> {
205→  const workspaceRecord = new RecordId("workspace", workspaceId);
206→
207→  // Two-step: get workspace member identities, then find their agents
208→  const result = await surreal.query<[unknown, Array<{
209→    id: RecordId;
210→    name: string;
211→    description: string;
212→  }>]>(
213→    `LET $members = (SELECT VALUE in FROM member_of WHERE out = $ws);
214→     SELECT id, name, description FROM agent
215→     WHERE managed_by IN $members
216→     AND description IS NOT NONE;`,
217→    { ws: workspaceRecord },
218→  );
219→
220→  return (result[1] ?? []).map((a) => ({
221→    agentId: a.id.id as string,
222→    agentType: a.name,
223→    description: a.description,
224→  }));
225→}
226→
227→/**
228→ * Resolves the target entity for an observation by querying the observes edge.
229→ */
230→async function resolveObservationTarget(
231→  surreal: Surreal,
232→  observationId: string,
233→): Promise<{ table: string; id: string } | undefined> {
234→  const obsRecord = new RecordId("observation", observationId);
235→  const result = await surreal.query<[Array<{ out: RecordId }>]>(
236→    `SELECT out FROM observes WHERE in = $obs LIMIT 1;`,
237→    { obs: obsRecord },
238→  );
239→  const edge = result[0]?.[0];
240→  if (edge?.out instanceof RecordId) {
241→    return { table: edge.out.table.name, id: edge.out.id as string };
242→  }
243→  return undefined;
244→}
245→
246→/**
247→ * Checks whether the observation's target entity already has an active
248→ * agent session. If so, the proxy handles context enrichment.
249→ */
250→async function hasActiveCoverage(
251→  surreal: Surreal,
252→  target: { table: string; id: string },
253→  workspaceId: string,
254→): Promise<boolean> {
255→  const workspaceRecord = new RecordId("workspace", workspaceId);
256→  const taskRecord = new RecordId(target.table, target.id);
257→
258→  const result = await surreal.query<[Array<{ count: number }>]>(
259→    `SELECT count() AS count FROM agent_session
260→     WHERE task_id = $task AND workspace = $ws AND orchestrator_status = "active"
261→     LIMIT 1;`,
262→    { task: taskRecord, ws: workspaceRecord },
263→  );
264→
265→  const count = result[0]?.[0]?.count ?? 0;
266→  return count > 0;
267→}
268→
269→/**
270→ * Creates a new agent session for a matched agent, marking it as "spawning".
271→ */
272→async function createActivatedSession(
273→  surreal: Surreal,
274→  match: { agentType: string; workspaceId: string; observationId: string },
275→): Promise<string> {
276→  const sessionId = `sess-${crypto.randomUUID()}`;
277→  const sessionRecord = new RecordId("agent_session", sessionId);
278→  const workspaceRecord = new RecordId("workspace", match.workspaceId);
279→  const observationRecord = new RecordId("observation", match.observationId);
280→
281→  await surreal.query(`CREATE $sess CONTENT $content;`, {
282→    sess: sessionRecord,
283→    content: {
284→      agent: match.agentType,
285→      started_at: new Date(),
286→      workspace: workspaceRecord,
287→      orchestrator_status: "spawning",
288→      source: "activator",
289→      triggered_by: observationRecord,
290→      created_at: new Date(),
291→    },
292→  });
293→
294→  return sessionId;
295→}
296→
297→/**
298→ * Creates a provisional decision recording the activator's routing choice.
299→ * Only for conflict/warning severity observations. Links to the observation
300→ * via relates_to edge. Appears in the governance feed for human oversight.
301→ */
302→async function createActivationDecision(
303→  surreal: Surreal,
304→  workspaceId: string,
305→  observationId: string,
306→  observationText: string,
307→  severity: string,
308→  activatedAgents: Array<{ agentType: string; reason: string }>,
309→): Promise<string> {
310→  const decisionId = `dec-act-${crypto.randomUUID()}`;
311→  const decisionRecord = new RecordId("decision", decisionId);
312→  const workspaceRecord = new RecordId("workspace", workspaceId);
313→  const observationRecord = new RecordId("observation", observationId);
314→
315→  const agentSummary = activatedAgents.length > 0
316→    ? activatedAgents.map((a) => `${a.agentType}: ${a.reason}`).join("; ")
317→    : "No agents matched — observation logged for future context";
318→
319→  const summary = activatedAgents.length > 0
320→    ? `Activated ${activatedAgents.length} agent(s) for ${severity} observation`
321→    : `No agents activated for ${severity} observation`;
322→
323→  await surreal.query(`CREATE $dec CONTENT $content;`, {
324→    dec: decisionRecord,
325→    content: {
326→      summary,
327→      rationale: `Observation: "${observationText}"\n\nRouting: ${agentSummary}`,
328→      status: "provisional",
329→      inferred_by: "agent_activator",
330→      category: "operations",
331→      workspace: workspaceRecord,
332→      based_on: [observationRecord],
333→      created_at: new Date(),
334→      updated_at: new Date(),
335→    },
336→  });
337→
338→  // Link decision to observation
339→  await surreal.query(
340→    `RELATE $dec->relates_to->$obs SET created_at = time::now();`,
341→    { dec: decisionRecord, obs: observationRecord },
342→  );
343→
344→  return decisionId;
345→}
346→
347→/**
348→ * Creates a governance observation when the LLM hallucinates unknown agent IDs.
349→ * Makes the hallucination visible in the feed for human oversight.
350→ */
351→async function createHallucinationObservation(
352→  surreal: Surreal,
353→  workspaceId: string,
354→  observationId: string,
355→  hallucinatedIds: string[],
356→): Promise<void> {
357→  const metaId = `meta-halluc-${crypto.randomUUID()}`;
358→  const metaRecord = new RecordId("observation", metaId);
359→  const workspaceRecord = new RecordId("workspace", workspaceId);
360→  const sourceObsRecord = new RecordId("observation", observationId);
361→
362→  await surreal.query(`CREATE $obs CONTENT $content;`, {
363→    obs: metaRecord,
364→    content: {
365→      text: `Agent activator LLM hallucinated ${hallucinatedIds.length} agent ID(s) for observation ${observationId}: ${hallucinatedIds.join(", ")}`,
366→      severity: "info",
367→      status: "open",
368→      category: "engineering",
369→      source_agent: "agent_activator",
370→      workspace: workspaceRecord,
371→      created_at: new Date(),
372→      updated_at: new Date(),
373→    },
374→  });
375→
376→  // Link to the source observation
377→  await surreal.query(
