      .relate(identityRecord, new RecordId("member_of", "test-composite-member"), workspaceRecord, {
        role: "member",
        added_at: new Date(),
      })
      .output("after");

    // Name match (resolves via identity table)
    const byName = await resolveWorkspaceIdentity({
      surreal,
      workspaceRecord,
      identityName: "Alice",
    });
