184→async function ensureSingleAgent(
185→  surreal: Surreal,
186→  workspaceRecord: RecordId<"workspace", string>,
187→  ownerIdentity: RecordId<"identity", string>,
188→  template: AgentTemplate,
189→): Promise<void> {
190→  const existing = await findExistingIdentity(surreal, workspaceRecord, "agent", template.role);
191→  if (existing) {
192→    log.info("identity.bootstrap.agent_exists", "Agent identity already exists, skipping", {
193→      workspaceId: workspaceRecord.id as string,
194→      role: template.role,
195→    });
196→    return;
197→  }
198→
199→  const now = new Date();
200→  const agentRecord = buildAgentRecord();
201→  const identityRecord = buildIdentityRecord();
202→
203→  // Create agent record with managed_by pointing to owner identity
204→  await surreal.create(agentRecord).content({
205→    runtime: "brain" as const,
206→    name: template.name,
207→    managed_by: ownerIdentity,
208→    created_at: now,
209→  });
210→
211→  // Create agent identity hub
212→  await surreal.create(identityRecord).content({
213→    name: template.name,
214→    type: "agent" as const,
215→    role: template.role,
216→    workspace: workspaceRecord,
217→    created_at: now,
218→  });
219→
220→  // Create spoke edge from identity to agent
221→  await surreal
222→    .relate(identityRecord, new RecordId("identity_agent", randomUUID()), agentRecord, {
223→      added_at: now,
224→    })
225→    .output("after");
226→
227→  // Create member_of edge from identity to workspace
228→  await surreal
229→    .relate(identityRecord, new RecordId("member_of", randomUUID()), workspaceRecord, {
230→      role: "agent",
231→      added_at: now,
232→    })
233→    .output("after");
234→
235→  // Create authorized_to edges for each action
236→  await createAuthorityEdges(surreal, identityRecord, template.permissions, now);
237→
238→  log.info("identity.bootstrap.agent_created", "Agent identity created", {
239→    workspaceId: workspaceRecord.id as string,
240→    role: template.role,
241→  });
242→}
243→
244→async function createAuthorityEdges(
245→  surreal: Surreal,
246→  identityRecord: RecordId<"identity", string>,
247→  permissions: Record<string, AuthorityPermission>,
248→  now: Date,
249→): Promise<void> {
250→  // Look up all global authority_scope records
251→  const [scopeRows] = await surreal.query<[Array<{ id: RecordId<"authority_scope", string>; action: string }>]>(
252→    "SELECT id, action FROM authority_scope WHERE workspace IS NONE;",
253→  );
254→
255→  for (const scopeRow of scopeRows) {
256→    const permission = permissions[scopeRow.action];
257→    if (!permission) continue;
258→
259→    await surreal
260→      .relate(
261→        identityRecord,
262→        new RecordId("authorized_to", randomUUID()),
263→        scopeRow.id,
264→        { permission, created_at: now },
265→      )
266→      .output("after");
267→  }
268→}
