245→async function handleWorkspaceBootstrap(deps: ServerDependencies, workspaceId: string): Promise<Response> {
246→  const startedAt = performance.now();
247→  log.info("workspace.bootstrap.started", "Workspace bootstrap started", { workspaceId });
248→
249→  try {
250→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
251→    const workspace = await deps.surreal.select<WorkspaceRow>(workspaceRecord);
252→    if (!workspace) {
253→      throw new HttpError(404, `workspace not found: ${workspaceId}`);
254→    }
255→
256→    const conversationRecord = await resolveWorkspaceBootstrapConversation(deps, workspaceRecord);
257→    const conversationId = conversationRecord.id as string;
258→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
259→
260→    const messages = rawMessages.map((row) => ({
261→      id: row.id,
262→      role: row.role,
263→      text: row.text,
264→      createdAt: toIsoString(row.createdAt),
265→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
266→      ...(row.inherited ? { inherited: true } : {}),
267→      ...(row.subagent_traces && row.subagent_traces.length > 0 ? { subagentTraces: row.subagent_traces } : {}),
268→    } satisfies WorkspaceBootstrapMessage));
269→
270→    const seeds = await loadWorkspaceSeeds(deps, workspaceRecord, 40);
271→    const onboardingState = toOnboardingState(workspace);
272→    const sidebar = await buildWorkspaceConversationSidebar(deps.surreal, workspaceRecord);
273→
274→    const payload: WorkspaceBootstrapResponse = {
275→      workspaceId: workspace.id.id as string,
276→      workspaceName: workspace.name,
277→      ...(workspace.description ? { workspaceDescription: workspace.description } : {}),
278→      ...(workspace.repo_path ? { repoPath: workspace.repo_path } : {}),
279→      onboardingComplete: workspace.onboarding_complete,
280→      onboardingState,
281→      conversationId: conversationRecord.id as string,
282→      messages,
283→      seeds,
284→      sidebar,
285→    };
286→
287→    log.info("workspace.bootstrap.completed", "Workspace bootstrap completed", {
288→      workspaceId,
289→      conversationId: conversationRecord.id as string,
290→      messageCount: messages.length,
291→      seedCount: seeds.length,
292→      durationMs: elapsedMs(startedAt),
293→    });
294→
295→    return jsonResponse(payload, 200);
296→  } catch (error) {
297→    if (error instanceof HttpError) {
298→      log.warn("workspace.bootstrap.http_error", "Workspace bootstrap failed with client-facing error", {
299→        workspaceId,
300→        statusCode: error.status,
301→      });
302→      return jsonError(error.message, error.status);
