644→  from: string;
645→  to: string;
646→  trigger: "auto" | "manual";
647→  timestamp: string;
648→};
649→
650→type WorkspaceSettingsResponse = {
651→  enforcementMode: string;
652→  thresholds: {
653→    min_decisions: number;
654→    min_tasks: number;
655→  };
656→  transitions: EnforcementTransitionResponse[];
657→};
658→
659→const VALID_ENFORCEMENT_MODES: ReadonlySet<string> = new Set(["bootstrap", "soft", "hard"]);
660→
661→async function resolveSessionIdentity(
662→  deps: ServerDependencies,
663→  request: Request,
664→): Promise<{ personRecord: RecordId<"person", string> } | Response> {
665→  const session = await deps.auth.api.getSession({ headers: request.headers });
666→  if (!session?.user?.id) {
667→    return jsonError("authentication required", 401);
668→  }
669→
670→  const personRecord = new RecordId("person", session.user.id);
671→
672→  const [identityRows] = await deps.surreal.query<[RecordId<"identity", string>[]]>(
673→    "SELECT VALUE in FROM identity_person WHERE out = $person LIMIT 1;",
674→    { person: personRecord },
675→  );
676→  if (!identityRows[0]) {
677→    return jsonError("identity not found for user", 401);
678→  }
679→
680→  return { personRecord };
681→}
682→
683→function isSettingsResponse(value: unknown): value is Response {
684→  return value instanceof Response;
685→}
686→
687→function formatTransition(transition: EnforcementTransitionRow): EnforcementTransitionResponse {
688→  const timestamp = transition.timestamp instanceof Date
689→    ? transition.timestamp.toISOString()
690→    : typeof transition.timestamp === "string"
691→      ? transition.timestamp
692→      : new Date(transition.timestamp as unknown as number).toISOString();
693→  return {
694→    from: transition.from,
695→    to: transition.to,
696→    trigger: transition.trigger,
697→    timestamp,
698→  };
699→}
