746→
747→async function handlePutSettings(
748→  deps: ServerDependencies,
749→  workspaceId: string,
750→  request: Request,
751→): Promise<Response> {
752→  const identityOrError = await resolveSessionIdentity(deps, request);
753→  if (isSettingsResponse(identityOrError)) return identityOrError;
754→
755→  let body: unknown;
756→  try {
757→    body = await request.json();
758→  } catch {
759→    return jsonError("Request body must be valid JSON", 400);
760→  }
761→
762→  if (!body || typeof body !== "object") {
763→    return jsonError("Body must be an object", 400);
764→  }
765→
766→  const { enforcementMode, thresholds } = body as {
767→    enforcementMode?: string;
768→    thresholds?: { min_decisions?: number; min_tasks?: number };
769→  };
770→
771→  // Validate enforcementMode if provided
772→  if (enforcementMode !== undefined) {
773→    if (typeof enforcementMode !== "string" || !VALID_ENFORCEMENT_MODES.has(enforcementMode)) {
774→      return jsonError(`enforcementMode must be one of: bootstrap, soft, hard`, 400);
775→    }
776→  }
777→
778→  // Validate thresholds if provided
779→  if (thresholds !== undefined) {
780→    if (typeof thresholds !== "object") {
781→      return jsonError("thresholds must be an object", 400);
782→    }
783→    if (thresholds.min_decisions !== undefined) {
784→      if (!Number.isInteger(thresholds.min_decisions) || thresholds.min_decisions < 0) {
785→        return jsonError("thresholds.min_decisions must be a non-negative integer", 400);
786→      }
787→    }
788→    if (thresholds.min_tasks !== undefined) {
789→      if (!Number.isInteger(thresholds.min_tasks) || thresholds.min_tasks < 0) {
790→        return jsonError("thresholds.min_tasks must be a non-negative integer", 400);
791→      }
792→    }
793→  }
794→
795→  try {
796→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
797→
798→    // Read current enforcement mode to detect transitions
799→    const [currentRows] = await deps.surreal.query<[Array<{ evidence_enforcement?: string }>]>(
800→      "SELECT evidence_enforcement FROM $ws;",
801→      { ws: workspaceRecord },
802→    );
803→    const currentMode = currentRows[0]?.evidence_enforcement ?? "bootstrap";
804→
805→    // Build SET clauses for provided fields only
806→    const setClauses: string[] = [];
807→    const bindings: Record<string, unknown> = { ws: workspaceRecord };
808→
809→    if (enforcementMode !== undefined) {
810→      setClauses.push("evidence_enforcement = $mode");
811→      bindings.mode = enforcementMode;
812→
813→      // Append transition entry when mode actually changes
814→      if (enforcementMode !== currentMode) {
815→        const transitionEntry = {
816→          from: currentMode,
817→          to: enforcementMode,
818→          trigger: "manual" as const,
819→          timestamp: new Date(),
820→        };
821→        setClauses.push("evidence_enforcement_transitions = array::append(evidence_enforcement_transitions ?? [], $transition)");
822→        bindings.transition = transitionEntry;
823→      }
824→    }
825→
826→    if (thresholds !== undefined) {
827→      // Merge provided threshold fields with existing
828→      if (thresholds.min_decisions !== undefined) {
829→        setClauses.push("evidence_enforcement_threshold.min_decisions = $minDec");
830→        bindings.minDec = thresholds.min_decisions;
831→      }
832→      if (thresholds.min_tasks !== undefined) {
833→        setClauses.push("evidence_enforcement_threshold.min_tasks = $minTasks");
834→        bindings.minTasks = thresholds.min_tasks;
835→      }
836→    }
837→
838→    if (setClauses.length === 0) {
839→      return jsonError("No valid fields to update", 400);
840→    }
841→
842→    setClauses.push("updated_at = time::now()");
843→
844→    await deps.surreal.query(
845→      `UPDATE $ws SET ${setClauses.join(", ")};`,
846→      bindings,
847→    );
848→
849→    // Read back the updated settings
850→    const [rows] = await deps.surreal.query<[WorkspaceSettingsRow[]]>(
851→      "SELECT evidence_enforcement, evidence_enforcement_threshold, evidence_enforcement_transitions FROM $ws;",
852→      { ws: workspaceRecord },
853→    );
854→
855→    if (!rows[0]) {
856→      return jsonError("workspace not found", 404);
857→    }
858→
859→    return jsonResponse(toSettingsResponse(rows[0]), 200);
860→  } catch (error) {
861→    if (error instanceof HttpError) {
862→      return jsonError(error.message, error.status);
863→    }
864→
865→    log.error("workspace.settings.put.failed", "Failed to update workspace settings", error, { workspaceId });
866→    return jsonError("failed to update workspace settings", 500);
867→  }
868→}
