 63→  { role: "coder", name: "Code Agent", permissions: CODER_PERMISSIONS },
 64→  { role: "observer", name: "Observer Agent", permissions: OBSERVER_PERMISSIONS },
 65→] as const;
 66→
 67→// -- Pure helpers --
 68→
 69→const buildIdentityRecord = () => new RecordId("identity", randomUUID());
 70→const buildAgentRecord = () => new RecordId("agent", randomUUID());
 71→
 72→// -- Bootstrap pipeline --
 73→
 74→/**
 75→ * Bootstrap identity hub-and-spoke for a workspace.
 76→ * Wraps the owner person in an identity hub, creates template agent identities,
 77→ * and links each agent's managed_by to the owner identity.
 78→ *
 79→ * Idempotent: checks for existing identities before creating.
 80→ */
 81→export async function bootstrapWorkspaceIdentities(
 82→  surreal: Surreal,
 83→  workspaceRecord: RecordId<"workspace", string>,
 84→  ownerPersonRecord: RecordId<"person", string>,
 85→): Promise<void> {
 86→  const ownerIdentity = await ensureOwnerIdentity(
 87→    surreal,
 88→    workspaceRecord,
 89→    ownerPersonRecord,
 90→  );
 91→
 92→  await ensureTemplateAgents(surreal, workspaceRecord, ownerIdentity);
 93→
 94→  log.info("identity.bootstrap.completed", "Identity bootstrap completed", {
 95→    workspaceId: workspaceRecord.id as string,
 96→  });
 97→}
 98→
 99→// -- Owner identity --
100→
101→async function findExistingIdentity(
102→  surreal: Surreal,
103→  workspaceRecord: RecordId<"workspace", string>,
104→  type: IdentityType,
105→  role: string,
106→): Promise<RecordId<"identity", string> | undefined> {
107→  const [rows] = await surreal.query<
108→    [Array<{ id: RecordId<"identity", string> }>]
109→  >(
110→    "SELECT id FROM identity WHERE workspace = $ws AND type = $type AND role = $role LIMIT 1;",
111→    { ws: workspaceRecord, type, role },
112→  );
113→
114→  return rows.length > 0 ? rows[0].id : undefined;
115→}
116→
117→async function resolveOwnerName(
118→  surreal: Surreal,
119→  ownerPersonRecord: RecordId<"person", string>,
120→): Promise<string> {
121→  const person = await surreal.select<{ name: string }>(ownerPersonRecord);
122→  return person?.name ?? "Owner";
123→}
124→
125→async function ensureOwnerIdentity(
126→  surreal: Surreal,
127→  workspaceRecord: RecordId<"workspace", string>,
128→  ownerPersonRecord: RecordId<"person", string>,
129→): Promise<RecordId<"identity", string>> {
130→  const existing = await findExistingIdentity(surreal, workspaceRecord, "human", "owner");
131→  if (existing) {
132→    log.info("identity.bootstrap.owner_exists", "Owner identity already exists, skipping", {
133→      workspaceId: workspaceRecord.id as string,
134→    });
135→    return existing;
136→  }
137→
138→  const ownerName = await resolveOwnerName(surreal, ownerPersonRecord);
139→  const identityRecord = buildIdentityRecord();
140→  const now = new Date();
141→
142→  await surreal.create(identityRecord).content({
143→    name: ownerName,
144→    type: "human" as const,
145→    role: "owner",
146→    workspace: workspaceRecord,
147→    created_at: now,
148→  });
149→
150→  await surreal
151→    .relate(identityRecord, new RecordId("identity_person", randomUUID()), ownerPersonRecord, {
152→      added_at: now,
153→    })
154→    .output("after");
155→
156→  // Create member_of relation from identity to workspace (identity is now the actor for all relations)
157→  await surreal
158→    .relate(identityRecord, new RecordId("member_of", randomUUID()), workspaceRecord, {
159→      role: "owner",
160→      added_at: now,
161→    })
162→    .output("after");
163→
164→  log.info("identity.bootstrap.owner_created", "Owner identity created", {
165→    workspaceId: workspaceRecord.id as string,
166→    identityId: identityRecord.id as string,
167→  });
168→
169→  return identityRecord;
170→}
171→
172→// -- Template agents --
173→
174→async function ensureTemplateAgents(
175→  surreal: Surreal,
176→  workspaceRecord: RecordId<"workspace", string>,
177→  ownerIdentity: RecordId<"identity", string>,
178→): Promise<void> {
179→  for (const template of TEMPLATE_AGENTS) {
180→    await ensureSingleAgent(surreal, workspaceRecord, ownerIdentity, template);
181→  }
182→}
183→
184→async function ensureSingleAgent(
185→  surreal: Surreal,
186→  workspaceRecord: RecordId<"workspace", string>,
187→  ownerIdentity: RecordId<"identity", string>,
188→  template: AgentTemplate,
189→): Promise<void> {
190→  const existing = await findExistingIdentity(surreal, workspaceRecord, "agent", template.role);
191→  if (existing) {
192→    log.info("identity.bootstrap.agent_exists", "Agent identity already exists, skipping", {
193→      workspaceId: workspaceRecord.id as string,
194→      role: template.role,
195→    });
196→    return;
197→  }
198→
199→  const now = new Date();
200→  const agentRecord = buildAgentRecord();
201→  const identityRecord = buildIdentityRecord();
202→
203→  // Create agent record with managed_by pointing to owner identity
204→  await surreal.create(agentRecord).content({
205→    runtime: "brain" as const,
206→    name: template.name,
207→    managed_by: ownerIdentity,
208→    created_at: now,
209→  });
210→
211→  // Create agent identity hub
212→  await surreal.create(identityRecord).content({
213→    name: template.name,
214→    type: "agent" as const,
215→    role: template.role,
216→    workspace: workspaceRecord,
217→    created_at: now,
218→  });
219→
220→  // Create spoke edge from identity to agent
221→  await surreal
222→    .relate(identityRecord, new RecordId("identity_agent", randomUUID()), agentRecord, {
223→      added_at: now,
224→    })
225→    .output("after");
226→
227→  // Create member_of edge from identity to workspace
228→  await surreal
229→    .relate(identityRecord, new RecordId("member_of", randomUUID()), workspaceRecord, {
230→      role: "agent",
231→      added_at: now,
232→    })
233→    .output("after");
234→
235→  // Create authorized_to edges for each action
236→  await createAuthorityEdges(surreal, identityRecord, template.permissions, now);
237→
238→  log.info("identity.bootstrap.agent_created", "Agent identity created", {
239→    workspaceId: workspaceRecord.id as string,
240→    role: template.role,
241→  });
242→}
243→
244→async function createAuthorityEdges(
245→  surreal: Surreal,
246→  identityRecord: RecordId<"identity", string>,
247→  permissions: Record<string, AuthorityPermission>,
248→  now: Date,
249→): Promise<void> {
250→  // Look up all global authority_scope records
251→  const [scopeRows] = await surreal.query<[Array<{ id: RecordId<"authority_scope", string>; action: string }>]>(
252→    "SELECT id, action FROM authority_scope WHERE workspace IS NONE;",
253→  );
254→
255→  for (const scopeRow of scopeRows) {
256→    const permission = permissions[scopeRow.action];
257→    if (!permission) continue;
258→
259→    await surreal
260→      .relate(
261→        identityRecord,
262→        new RecordId("authorized_to", randomUUID()),
263→        scopeRow.id,
264→        { permission, created_at: now },
265→      )
266→      .output("after");
267→  }
268→}
