465→async function handleWorkspaceConversation(
466→  deps: ServerDependencies,
467→  workspaceId: string,
468→  conversationId: string,
469→): Promise<Response> {
470→  const startedAt = performance.now();
471→  log.info("workspace.conversation.started", "Workspace conversation request started", {
472→    workspaceId,
473→    conversationId,
474→  });
475→
476→  try {
477→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
478→    const conversationRecord = new RecordId("conversation", conversationId);
479→    const conversation = await deps.surreal.select<{
480→      id: RecordId<"conversation", string>;
481→      workspace: RecordId<"workspace", string>;
482→      discusses?: RecordId;
483→    }>(conversationRecord);
484→
485→    if (!conversation) {
486→      throw new HttpError(404, `conversation not found: ${conversationId}`);
487→    }
488→
489→    if ((conversation.workspace.id as string) !== (workspaceRecord.id as string)) {
490→      throw new HttpError(400, "conversation does not belong to workspace");
491→    }
492→
493→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
494→
495→    const messages = rawMessages.map((row) => ({
496→      id: row.id,
497→      role: row.role,
498→      text: row.text,
499→      createdAt: toIsoString(row.createdAt),
500→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
501→      ...(row.inherited ? { inherited: true } : {}),
502→      ...(row.subagent_traces && row.subagent_traces.length > 0 ? { subagentTraces: row.subagent_traces } : {}),
503→    } satisfies WorkspaceBootstrapMessage));
504→
505→    let discussEntity: DiscussEntitySummary | undefined;
506→    if (conversation.discusses) {
507→      const entityRecord = conversation.discusses as GraphEntityRecord;
508→      const name = await readEntityName(deps.surreal, entityRecord);
509→      if (name) {
510→        const entityRow = await deps.surreal.select<Record<string, unknown>>(entityRecord);
511→        discussEntity = {
512→          id: `${entityRecord.table.name}:${entityRecord.id as string}`,
513→          kind: entityRecord.table.name as EntityKind,
514→          name,
515→          ...(entityRow && typeof entityRow.status === "string" ? { status: entityRow.status } : {}),
516→        };
517→      }
518→    }
519→
520→    const payload: WorkspaceConversationResponse = {
521→      conversationId,
522→      messages,
523→      ...(discussEntity ? { discussEntity } : {}),
524→    };
525→
526→    log.info("workspace.conversation.completed", "Workspace conversation request completed", {
527→      workspaceId,
528→      conversationId,
529→      messageCount: messages.length,
530→      durationMs: elapsedMs(startedAt),
531→    });
532→
533→    return jsonResponse(payload, 200);
534→  } catch (error) {
535→    if (error instanceof HttpError) {
536→      log.warn("workspace.conversation.http_error", "Workspace conversation failed with client-facing error", {
537→        workspaceId,
538→        conversationId,
539→        statusCode: error.status,
540→      });
541→      return jsonError(error.message, error.status);
542→    }
543→
544→    log.error("workspace.conversation.failed", "Workspace conversation request failed", error, {
545→      workspaceId,
546→      conversationId,
547→    });
548→    const errorText = error instanceof Error ? error.message : "workspace conversation failed";
549→    return jsonError(errorText, 500);
550→  }
551→}
