196→      title: "Onboarding",
197→      title_source: "message",
198→    });
199→
200→    await transaction.create(starterMessageRecord).content({
201→      conversation: conversationRecord,
202→      role: "assistant",
203→      text: starterMessage,
204→      suggestions: starterSuggestions,
205→      createdAt: now,
206→    });
207→
208→    await transaction.commit();
209→  } catch (error) {
210→    await transaction.cancel();
211→    log.error("workspace.create.failed", "Workspace creation failed", error, {
212→      workspaceId,
213→      conversationId,
214→    });
215→    const errorText = error instanceof Error ? error.message : "workspace creation failed";
216→    return jsonError(errorText, 500);
217→  }
218→
219→  // Bootstrap identity hub-and-spoke (non-blocking: workspace creation succeeds even if bootstrap fails)
220→  try {
221→    await bootstrapWorkspaceIdentities(deps.surreal, workspaceRecord, ownerRecord);
222→  } catch (error) {
223→    log.warn("workspace.create.identity_bootstrap_failed", "Identity bootstrap failed but workspace creation succeeded", {
224→      workspaceId,
