311→async function resolveWorkspaceBootstrapConversation(
312→  deps: ServerDependencies,
313→  workspaceRecord: RecordId<"workspace", string>,
314→): Promise<RecordId<"conversation", string>> {
315→  const [onboardingRows] = await deps.surreal
316→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
317→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace AND source = 'onboarding' ORDER BY createdAt ASC LIMIT 1;",
318→      {
319→        workspace: workspaceRecord,
320→      },
321→    )
322→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
323→
324→  if (onboardingRows.length > 0) {
325→    return onboardingRows[0].id;
326→  }
327→
328→  const [latestRows] = await deps.surreal
329→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
330→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace ORDER BY createdAt DESC LIMIT 1;",
331→      {
332→        workspace: workspaceRecord,
333→      },
334→    )
335→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
336→
337→  if (latestRows.length > 0) {
338→    return latestRows[0].id;
339→  }
340→
341→  const now = new Date();
342→  const conversationRecord = new RecordId("conversation", randomUUID());
343→  await deps.surreal.create(conversationRecord).content({
344→    createdAt: now,
345→    updatedAt: now,
346→    workspace: workspaceRecord,
347→    source: "onboarding",
348→  });
349→  return conversationRecord;
350→}
