362→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
363→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
364→  if (!response.ok || !response.body) {
365→    throw new Error(`Failed to open SSE stream (${response.status})`);
366→  }
367→
368→  const reader = response.body.getReader();
369→  const decoder = new TextDecoder();
370→  const events: T[] = [];
371→  let buffer = "";
372→
373→  const timeout = setTimeout(() => {
374→    void reader.cancel();
375→  }, timeoutMs);
376→
377→  try {
378→    while (true) {
379→      const { value, done } = await reader.read();
380→      if (done) {
381→        break;
382→      }
383→
384→      buffer += decoder.decode(value, { stream: true });
385→      const segments = buffer.split("\n\n");
386→      buffer = segments.pop() ?? "";
387→
388→      for (const segment of segments) {
389→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
390→        if (!dataLine) {
391→          continue;
392→        }
393→
394→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
395→        events.push(event);
396→
397→        if (event.type === "error") {
398→          const errorText = (event as { error?: string }).error;
399→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
400→        }
401→
402→        if (event.type === "done") {
403→          return events;
404→        }
405→      }
406→    }
407→  } finally {
408→    clearTimeout(timeout);
409→    reader.releaseLock();
410→  }
411→
412→  return events;
413→}
