125→async function ensureOwnerIdentity(
126→  surreal: Surreal,
127→  workspaceRecord: RecordId<"workspace", string>,
128→  ownerPersonRecord: RecordId<"person", string>,
129→): Promise<RecordId<"identity", string>> {
130→  const existing = await findExistingIdentity(surreal, workspaceRecord, "human", "owner");
131→  if (existing) {
132→    log.info("identity.bootstrap.owner_exists", "Owner identity already exists, skipping", {
133→      workspaceId: workspaceRecord.id as string,
134→    });
135→    return existing;
136→  }
137→
138→  const ownerName = await resolveOwnerName(surreal, ownerPersonRecord);
139→  const identityRecord = buildIdentityRecord();
140→  const now = new Date();
141→
142→  await surreal.create(identityRecord).content({
143→    name: ownerName,
144→    type: "human" as const,
145→    role: "owner",
146→    workspace: workspaceRecord,
147→    created_at: now,
148→  });
149→
150→  await surreal
151→    .relate(identityRecord, new RecordId("identity_person", randomUUID()), ownerPersonRecord, {
152→      added_at: now,
153→    })
154→    .output("after");
155→
156→  // Create member_of relation from identity to workspace (identity is now the actor for all relations)
157→  await surreal
158→    .relate(identityRecord, new RecordId("member_of", randomUUID()), workspaceRecord, {
159→      role: "owner",
160→      added_at: now,
161→    })
162→    .output("after");
163→
164→  log.info("identity.bootstrap.owner_created", "Owner identity created", {
165→    workspaceId: workspaceRecord.id as string,
166→    identityId: identityRecord.id as string,
167→  });
168→
169→  return identityRecord;
170→}
